const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const dataDir = path.join(__dirname, 'data');
if (!fs.existsSync(dataDir)) {
  fs.mkdirSync(dataDir, { recursive: true });
}

const db = new Database(path.join(dataDir, 'urls.db'));

db.pragma('journal_mode = WAL');
db.pragma('foreign_keys = ON');

db.exec(`
  CREATE TABLE IF NOT EXISTS urls (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    slug TEXT NOT NULL UNIQUE,
    original_url TEXT NOT NULL,
    clicks INTEGER DEFAULT 0,
    created_at TEXT DEFAULT (datetime('now')),
    expires_at TEXT
  );

  CREATE TABLE IF NOT EXISTS click_log (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    slug TEXT NOT NULL,
    clicked_at TEXT DEFAULT (datetime('now')),
    ip TEXT,
    user_agent TEXT,
    FOREIGN KEY (slug) REFERENCES urls(slug) ON DELETE CASCADE
  );

  CREATE INDEX IF NOT EXISTS idx_urls_slug ON urls(slug);
  CREATE INDEX IF NOT EXISTS idx_click_log_slug ON click_log(slug);
`);

const stmts = {
  insertUrl: db.prepare(
    'INSERT INTO urls (slug, original_url, expires_at) VALUES (@slug, @originalUrl, @expiresAt)'
  ),
  getUrl: db.prepare('SELECT * FROM urls WHERE slug = ?'),
  getAllUrls: db.prepare('SELECT * FROM urls ORDER BY created_at DESC'),
  incrementClick: db.prepare('UPDATE urls SET clicks = clicks + 1 WHERE slug = ?'),
  logClick: db.prepare(
    'INSERT INTO click_log (slug, ip, user_agent) VALUES (@slug, @ip, @userAgent)'
  ),
  deleteUrl: db.prepare('DELETE FROM urls WHERE slug = ?'),
  getClickStats: db.prepare(
    `SELECT date(clicked_at) AS date, COUNT(*) AS count
     FROM click_log
     WHERE slug = ?
     GROUP BY date(clicked_at)
     ORDER BY date(clicked_at) DESC`
  ),
};

function createUrl({ slug, originalUrl, expiresAt }) {
  stmts.insertUrl.run({ slug, originalUrl, expiresAt });
  return stmts.getUrl.get(slug);
}

function getUrl(slug) {
  return stmts.getUrl.get(slug);
}

function getAllUrls() {
  return stmts.getAllUrls.all();
}

function incrementClick(slug) {
  stmts.incrementClick.run(slug);
}

function logClick({ slug, ip, userAgent }) {
  stmts.logClick.run({ slug, ip, userAgent });
}

function deleteUrl(slug) {
  const result = stmts.deleteUrl.run(slug);
  return result.changes > 0;
}

function getClickStats(slug) {
  return stmts.getClickStats.all(slug);
}

module.exports = {
  db,
  createUrl,
  getUrl,
  getAllUrls,
  incrementClick,
  logClick,
  deleteUrl,
  getClickStats,
};

const { Router } = require('express');
const crypto = require('crypto');
const db = require('./db');

const router = Router();

function generateSlug(length = 6) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  const bytes = crypto.randomBytes(length);
  let slug = '';
  for (let i = 0; i < length; i++) {
    slug += chars[bytes[i] % chars.length];
  }
  return slug;
}

// POST /api/shorten - Create shortened URL
router.post('/api/shorten', (req, res) => {
  const { url, customSlug, expiresIn = 720 } = req.body;

  if (!url) {
    return res.status(400).json({ error: 'url is required' });
  }

  try {
    new URL(url);
  } catch {
    return res.status(400).json({ error: 'Invalid URL format' });
  }

  let slug = customSlug || generateSlug();

  if (customSlug) {
    if (!/^[a-zA-Z0-9_-]+$/.test(customSlug)) {
      return res.status(400).json({ error: 'Custom slug may only contain letters, numbers, hyphens, and underscores' });
    }
    const existing = db.getUrl(customSlug);
    if (existing) {
      return res.status(409).json({ error: 'Slug already in use' });
    }
  } else {
    let attempts = 0;
    while (db.getUrl(slug) && attempts < 10) {
      slug = generateSlug();
      attempts++;
    }
    if (db.getUrl(slug)) {
      return res.status(500).json({ error: 'Failed to generate unique slug' });
    }
  }

  const expiresAt = new Date(Date.now() + expiresIn * 60 * 60 * 1000).toISOString();

  try {
    const record = db.createUrl({ slug, originalUrl: url, expiresAt });
    const protocol = req.protocol;
    const host = req.get('host');
    res.status(201).json({
      shortUrl: `${protocol}://${host}/${record.slug}`,
      slug: record.slug,
      originalUrl: record.original_url,
      expiresAt: record.expires_at,
    });
  } catch (err) {
    if (err.code === 'SQLITE_CONSTRAINT_UNIQUE') {
      return res.status(409).json({ error: 'Slug already in use' });
    }
    res.status(500).json({ error: 'Internal server error' });
  }
});

// GET /api/urls - List all URLs with click counts
router.get('/api/urls', (_req, res) => {
  const urls = db.getAllUrls();
  res.json(urls);
});

// GET /api/urls/:slug/stats - Get click statistics for a slug
router.get('/api/urls/:slug/stats', (req, res) => {
  const { slug } = req.params;
  const record = db.getUrl(slug);
  if (!record) {
    return res.status(404).json({ error: 'URL not found' });
  }

  const stats = db.getClickStats(slug);
  res.json({
    slug: record.slug,
    originalUrl: record.original_url,
    totalClicks: record.clicks,
    createdAt: record.created_at,
    expiresAt: record.expires_at,
    clicksByDate: stats,
  });
});

// DELETE /api/urls/:slug - Delete a URL
router.delete('/api/urls/:slug', (req, res) => {
  const { slug } = req.params;
  const deleted = db.deleteUrl(slug);
  if (!deleted) {
    return res.status(404).json({ error: 'URL not found' });
  }
  res.json({ message: 'Deleted' });
});

// GET /:slug - Redirect to original URL
router.get('/:slug', (req, res) => {
  const { slug } = req.params;
  const record = db.getUrl(slug);

  if (!record) {
    return res.status(404).json({ error: 'Short URL not found' });
  }

  if (record.expires_at && new Date(record.expires_at) < new Date()) {
    return res.status(410).json({ error: 'This short URL has expired' });
  }

  db.incrementClick(slug);
  db.logClick({
    slug,
    ip: req.ip,
    userAgent: req.get('user-agent') || '',
  });

  res.redirect(301, record.original_url);
});

module.exports = router;

const express = require('express');
const path = require('path');
const routes = require('./routes');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());
app.use(express.static(path.join(__dirname, 'public')));
app.use(routes);

app.listen(PORT, () => {
  console.log(`URL shortener running on http://localhost:${PORT}`);
});

module.exports = app;

/* ===== Reset & Base ===== */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

:root {
  --accent: #6C63FF;
  --accent-hover: #5a52e0;
  --accent-glow: rgba(108, 99, 255, 0.25);
  --bg: #0f1117;
  --bg-card: #181a24;
  --bg-input: #1e2030;
  --border: #2a2d3e;
  --text: #e4e4ec;
  --text-muted: #8b8da3;
  --text-dim: #555770;
  --danger: #ef4444;
  --danger-hover: #dc2626;
  --success: #22c55e;
  --radius: 10px;
  --radius-sm: 6px;
  --shadow: 0 2px 12px rgba(0, 0, 0, 0.3);
  --shadow-lg: 0 8px 32px rgba(0, 0, 0, 0.4);
  --transition: 0.2s ease;
}

html {
  font-size: 16px;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  min-height: 100vh;
}

/* ===== Layout ===== */
.container {
  max-width: 900px;
  margin: 0 auto;
  padding: 2rem 1.25rem 4rem;
}

/* ===== Header ===== */
header {
  text-align: center;
  margin-bottom: 2rem;
}

header h1 {
  font-size: 2rem;
  font-weight: 700;
  color: var(--accent);
  letter-spacing: -0.02em;
}

.subtitle {
  color: var(--text-muted);
  font-size: 0.95rem;
  margin-top: 0.25rem;
}

/* ===== Cards ===== */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1.75rem;
  margin-bottom: 1.5rem;
  box-shadow: var(--shadow);
}

.card h2 {
  font-size: 1.15rem;
  font-weight: 600;
  margin-bottom: 1.25rem;
}

/* ===== Form ===== */
.form-group {
  margin-bottom: 1rem;
  flex: 1;
}

.form-group label {
  display: block;
  font-size: 0.85rem;
  font-weight: 500;
  margin-bottom: 0.4rem;
  color: var(--text-muted);
}

.optional {
  color: var(--text-dim);
  font-weight: 400;
}

.form-row {
  display: flex;
  gap: 1rem;
}

input[type="url"],
input[type="text"],
select {
  width: 100%;
  padding: 0.65rem 0.85rem;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  color: var(--text);
  font-size: 0.95rem;
  font-family: inherit;
  transition: border-color var(--transition), box-shadow var(--transition);
  outline: none;
}

input:focus,
select:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-glow);
}

input::placeholder {
  color: var(--text-dim);
}

select option {
  background: var(--bg-card);
}

/* ===== Buttons ===== */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  font-family: inherit;
  font-size: 0.9rem;
  font-weight: 500;
  padding: 0.65rem 1.25rem;
  border-radius: var(--radius-sm);
  border: none;
  cursor: pointer;
  transition: background var(--transition), transform var(--transition), box-shadow var(--transition);
}

.btn:active {
  transform: scale(0.97);
}

.btn-primary {
  width: 100%;
  background: var(--accent);
  color: #fff;
  font-size: 0.95rem;
  padding: 0.75rem;
  margin-top: 0.5rem;
}

.btn-primary:hover {
  background: var(--accent-hover);
  box-shadow: 0 0 0 4px var(--accent-glow);
}

.btn-secondary {
  background: var(--bg-input);
  color: var(--text-muted);
  border: 1px solid var(--border);
}

.btn-secondary:hover {
  background: var(--border);
  color: var(--text);
}

.btn-sm {
  padding: 0.35rem 0.75rem;
  font-size: 0.8rem;
}

.btn-danger {
  background: transparent;
  color: var(--danger);
  border: 1px solid var(--danger);
  padding: 0.3rem 0.65rem;
  font-size: 0.78rem;
}

.btn-danger:hover {
  background: var(--danger);
  color: #fff;
}

.btn-stats {
  background: transparent;
  color: var(--accent);
  border: 1px solid var(--accent);
  padding: 0.3rem 0.65rem;
  font-size: 0.78rem;
}

.btn-stats:hover {
  background: var(--accent);
  color: #fff;
}

/* ===== Copy Button ===== */
.btn-copy {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: var(--radius-sm);
  padding: 0.5rem 0.85rem;
  cursor: pointer;
  font-family: inherit;
  font-size: 0.85rem;
  font-weight: 500;
  transition: background var(--transition), transform var(--transition);
  white-space: nowrap;
}

.btn-copy:hover {
  background: var(--accent-hover);
}

.btn-copy:active {
  transform: scale(0.95);
}

.btn-copy.copied {
  background: var(--success);
  animation: copyPulse 0.4s ease;
}

@keyframes copyPulse {
  0% { transform: scale(1); }
  50% { transform: scale(1.08); }
  100% { transform: scale(1); }
}

/* ===== Result ===== */
.result-section {
  margin-top: 1.5rem;
  padding-top: 1.5rem;
  border-top: 1px solid var(--border);
  animation: slideDown 0.3s ease;
}

@keyframes slideDown {
  from { opacity: 0; transform: translateY(-8px); }
  to { opacity: 1; transform: translateY(0); }
}

.result-label {
  font-size: 0.8rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin-bottom: 0.6rem;
}

.result-row {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 0.6rem 0.6rem 0.6rem 1rem;
}

.result-url {
  flex: 1;
  color: var(--accent);
  font-weight: 500;
  font-size: 1rem;
  text-decoration: none;
  word-break: break-all;
}

.result-url:hover {
  text-decoration: underline;
}

/* ===== URLs Table ===== */
.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1.25rem;
}

.section-header h2 {
  margin-bottom: 0;
}

.table-wrapper {
  overflow-x: auto;
  -webkit-overflow-scrolling: touch;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.88rem;
}

thead th {
  text-align: left;
  padding: 0.65rem 0.75rem;
  font-weight: 600;
  font-size: 0.78rem;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  color: var(--text-muted);
  border-bottom: 1px solid var(--border);
  white-space: nowrap;
}

tbody td {
  padding: 0.7rem 0.75rem;
  border-bottom: 1px solid var(--border);
  vertical-align: middle;
}

tbody tr {
  transition: background var(--transition);
}

tbody tr:hover {
  background: rgba(108, 99, 255, 0.05);
}

tbody tr:last-child td {
  border-bottom: none;
}

.cell-short a {
  color: var(--accent);
  text-decoration: none;
  font-weight: 500;
}

.cell-short a:hover {
  text-decoration: underline;
}

.cell-original {
  max-width: 220px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  color: var(--text-muted);
}

.cell-clicks {
  font-weight: 600;
  text-align: center;
}

.cell-date {
  white-space: nowrap;
  color: var(--text-muted);
  font-size: 0.82rem;
}

.cell-actions {
  display: flex;
  gap: 0.4rem;
  white-space: nowrap;
}

/* ===== Loading & Empty ===== */
.loading {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.75rem;
  padding: 2rem 0;
  color: var(--text-muted);
}

.spinner {
  width: 20px;
  height: 20px;
  border: 2px solid var(--border);
  border-top-color: var(--accent);
  border-radius: 50%;
  animation: spin 0.7s linear infinite;
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

.empty-state {
  text-align: center;
  padding: 2.5rem 1rem;
  color: var(--text-dim);
}

/* ===== Modal ===== */
.modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0, 0, 0, 0.65);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  padding: 1rem;
  animation: fadeIn 0.2s ease;
}

@keyframes fadeIn {
  from { opacity: 0; }
  to { opacity: 1; }
}

.modal {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  width: 100%;
  max-width: 560px;
  box-shadow: var(--shadow-lg);
  animation: modalSlide 0.25s ease;
}

@keyframes modalSlide {
  from { opacity: 0; transform: translateY(16px) scale(0.97); }
  to { opacity: 1; transform: translateY(0) scale(1); }
}

.modal-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 1.25rem 1.5rem;
  border-bottom: 1px solid var(--border);
}

.modal-header h3 {
  font-size: 1.05rem;
  font-weight: 600;
}

.btn-close {
  background: none;
  border: none;
  color: var(--text-muted);
  font-size: 1.5rem;
  cursor: pointer;
  padding: 0;
  line-height: 1;
  transition: color var(--transition);
}

.btn-close:hover {
  color: var(--text);
}

.modal-body {
  padding: 1.5rem;
}

/* ===== Stats Summary ===== */
.stats-summary {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 0.75rem;
  margin-bottom: 1.5rem;
}

.stat-card {
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 1rem;
  text-align: center;
  display: flex;
  flex-direction: column;
  gap: 0.2rem;
}

.stat-value {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--accent);
}

.stat-label {
  font-size: 0.75rem;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

/* ===== Bar Chart ===== */
.chart-section h4 {
  font-size: 0.85rem;
  font-weight: 500;
  color: var(--text-muted);
  margin-bottom: 1rem;
}

.bar-chart {
  display: flex;
  align-items: flex-end;
  gap: 6px;
  height: 160px;
  padding-top: 1rem;
}

.bar-column {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.35rem;
  height: 100%;
  justify-content: flex-end;
}

.bar {
  width: 100%;
  max-width: 48px;
  background: var(--accent);
  border-radius: 4px 4px 0 0;
  min-height: 4px;
  transition: height 0.5s ease, background 0.2s;
  position: relative;
}

.bar:hover {
  background: var(--accent-hover);
}

.bar-value {
  font-size: 0.72rem;
  font-weight: 600;
  color: var(--text);
}

.bar-label {
  font-size: 0.68rem;
  color: var(--text-dim);
  white-space: nowrap;
}

/* ===== Toast Notifications ===== */
.toast-container {
  position: fixed;
  bottom: 1.5rem;
  right: 1.5rem;
  z-index: 2000;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.toast {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 0.75rem 1.15rem;
  font-size: 0.88rem;
  color: var(--text);
  box-shadow: var(--shadow-lg);
  animation: toastIn 0.3s ease;
  max-width: 340px;
}

.toast.toast-error {
  border-left: 3px solid var(--danger);
}

.toast.toast-success {
  border-left: 3px solid var(--success);
}

.toast.toast-out {
  animation: toastOut 0.3s ease forwards;
}

@keyframes toastIn {
  from { opacity: 0; transform: translateX(24px); }
  to { opacity: 1; transform: translateX(0); }
}

@keyframes toastOut {
  from { opacity: 1; transform: translateX(0); }
  to { opacity: 0; transform: translateX(24px); }
}

/* ===== Responsive ===== */
@media (max-width: 640px) {
  .container {
    padding: 1.25rem 0.75rem 3rem;
  }

  .card {
    padding: 1.25rem;
  }

  .form-row {
    flex-direction: column;
    gap: 0;
  }

  header h1 {
    font-size: 1.6rem;
  }

  .stats-summary {
    grid-template-columns: 1fr;
  }

  .cell-original {
    max-width: 120px;
  }

  table {
    font-size: 0.82rem;
  }
}

(function () {
  "use strict";

  const API_BASE = "/api";

  // ===== DOM References =====
  const form = document.getElementById("shorten-form");
  const urlInput = document.getElementById("url-input");
  const slugInput = document.getElementById("slug-input");
  const expiresSelect = document.getElementById("expires-select");
  const submitBtn = document.getElementById("submit-btn");
  const resultSection = document.getElementById("result-section");
  const resultUrl = document.getElementById("result-url");
  const urlsTable = document.getElementById("urls-table");
  const urlsTbody = document.getElementById("urls-tbody");
  const urlsLoading = document.getElementById("urls-loading");
  const urlsEmpty = document.getElementById("urls-empty");
  const statsOverlay = document.getElementById("stats-overlay");
  const statsTitle = document.getElementById("stats-title");
  const statsTotal = document.getElementById("stats-total");
  const statsToday = document.getElementById("stats-today");
  const statsWeek = document.getElementById("stats-week");
  const statsChart = document.getElementById("stats-chart");
  const toastContainer = document.getElementById("toast-container");

  // ===== Shorten URL =====
  window.shortenUrl = async function (event) {
    event.preventDefault();

    const url = urlInput.value.trim();
    if (!url) return;

    const body = { url };
    const customSlug = slugInput.value.trim();
    if (customSlug) body.customSlug = customSlug;
    const expiresIn = expiresSelect.value;
    if (expiresIn) body.expiresIn = expiresIn;

    setSubmitLoading(true);

    try {
      const res = await fetch(`${API_BASE}/shorten`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || data.message || "Failed to shorten URL");
      }

      const shortUrl = data.shortUrl || `${location.origin}/${data.slug}`;
      resultUrl.href = shortUrl;
      resultUrl.textContent = shortUrl;
      resultSection.hidden = false;

      toast("URL shortened successfully!", "success");

      // Reset form fields but keep the result visible
      urlInput.value = "";
      slugInput.value = "";
      expiresSelect.value = "";

      // Refresh the URL list
      loadUrls();
    } catch (err) {
      toast(err.message, "error");
    } finally {
      setSubmitLoading(false);
    }
  };

  function setSubmitLoading(loading) {
    submitBtn.disabled = loading;
    submitBtn.querySelector(".btn-text").hidden = loading;
    submitBtn.querySelector(".btn-loading").hidden = !loading;
  }

  // ===== Load URLs =====
  window.loadUrls = async function () {
    urlsLoading.hidden = false;
    urlsTable.hidden = true;
    urlsEmpty.hidden = true;

    try {
      const res = await fetch(`${API_BASE}/urls`);
      if (!res.ok) throw new Error("Failed to load URLs");

      const data = await res.json();
      const urls = Array.isArray(data) ? data : data.urls || [];

      if (urls.length === 0) {
        urlsEmpty.hidden = false;
        urlsTable.hidden = true;
      } else {
        renderTable(urls);
        urlsTable.hidden = false;
        urlsEmpty.hidden = true;
      }
    } catch (err) {
      toast(err.message, "error");
      urlsEmpty.hidden = false;
    } finally {
      urlsLoading.hidden = true;
    }
  };

  function renderTable(urls) {
    urlsTbody.innerHTML = "";

    urls.forEach(function (item) {
      const tr = document.createElement("tr");
      const shortUrl = item.shortUrl || `${location.origin}/${item.slug}`;

      tr.innerHTML =
        '<td class="cell-short"><a href="' + escapeHtml(shortUrl) + '" target="_blank" rel="noopener">' +
          escapeHtml("/" + item.slug) +
        "</a></td>" +
        '<td class="cell-original" title="' + escapeAttr(item.url || item.originalUrl || "") + '">' +
          escapeHtml(item.url || item.originalUrl || "") +
        "</td>" +
        '<td class="cell-clicks">' + (item.clicks != null ? item.clicks : 0) + "</td>" +
        '<td class="cell-date">' + formatDate(item.createdAt) + "</td>" +
        '<td class="cell-date">' + (item.expiresAt ? formatDate(item.expiresAt) : "Never") + "</td>" +
        '<td><div class="cell-actions">' +
          '<button class="btn btn-stats" data-slug="' + escapeAttr(item.slug) + '">Stats</button>' +
          '<button class="btn btn-danger" data-slug="' + escapeAttr(item.slug) + '">Delete</button>' +
        "</div></td>";

      // Bind event listeners
      tr.querySelector(".btn-stats").addEventListener("click", function () {
        showStats(this.dataset.slug);
      });
      tr.querySelector(".btn-danger").addEventListener("click", function () {
        deleteUrl(this.dataset.slug);
      });

      urlsTbody.appendChild(tr);
    });
  }

  // ===== Delete URL =====
  window.deleteUrl = async function (slug) {
    if (!confirm("Delete this shortened URL? This cannot be undone.")) return;

    try {
      const res = await fetch(`${API_BASE}/urls/${encodeURIComponent(slug)}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        const data = await res.json().catch(function () { return {}; });
        throw new Error(data.error || "Failed to delete URL");
      }

      toast("URL deleted", "success");
      loadUrls();
    } catch (err) {
      toast(err.message, "error");
    }
  };

  // ===== Show Stats =====
  window.showStats = async function (slug) {
    statsTitle.textContent = "Stats for /" + slug;
    statsChart.innerHTML = '<div class="loading"><div class="spinner"></div></div>';
    statsTotal.textContent = "-";
    statsToday.textContent = "-";
    statsWeek.textContent = "-";
    statsOverlay.hidden = false;
    document.body.style.overflow = "hidden";

    try {
      const res = await fetch(`${API_BASE}/urls/${encodeURIComponent(slug)}/stats`);
      if (!res.ok) throw new Error("Failed to load statistics");

      const data = await res.json();

      statsTotal.textContent = data.totalClicks != null ? data.totalClicks : (data.clicks != null ? data.clicks : 0);
      statsToday.textContent = data.todayClicks != null ? data.todayClicks : 0;
      statsWeek.textContent = data.weekClicks != null ? data.weekClicks : 0;

      // Render daily chart
      var dailyData = data.daily || data.dailyClicks || [];
      if (dailyData.length === 0) {
        dailyData = buildEmptyWeek();
      }
      renderChart(dailyData);
    } catch (err) {
      toast(err.message, "error");
      statsChart.innerHTML = '<p style="text-align:center;color:var(--text-dim);">Could not load chart data</p>';
    }
  };

  window.closeStatsModal = function (event) {
    if (event && event.target !== statsOverlay) return;
    statsOverlay.hidden = true;
    document.body.style.overflow = "";
  };

  // Close modal on Escape
  document.addEventListener("keydown", function (e) {
    if (e.key === "Escape" && !statsOverlay.hidden) {
      closeStatsModal();
    }
  });

  function buildEmptyWeek() {
    var days = [];
    for (var i = 6; i >= 0; i--) {
      var d = new Date();
      d.setDate(d.getDate() - i);
      days.push({ date: d.toISOString().slice(0, 10), clicks: 0 });
    }
    return days;
  }

  function renderChart(dailyData) {
    var maxClicks = Math.max.apply(null, dailyData.map(function (d) { return d.clicks || 0; }));
    if (maxClicks === 0) maxClicks = 1;

    statsChart.innerHTML = "";

    dailyData.forEach(function (day) {
      var col = document.createElement("div");
      col.className = "bar-column";

      var clicks = day.clicks || 0;
      var heightPercent = (clicks / maxClicks) * 100;

      var value = document.createElement("span");
      value.className = "bar-value";
      value.textContent = clicks;

      var bar = document.createElement("div");
      bar.className = "bar";
      bar.style.height = Math.max(heightPercent, 3) + "%";
      bar.title = clicks + " clicks";

      var label = document.createElement("span");
      label.className = "bar-label";
      var dateObj = new Date(day.date + "T00:00:00");
      label.textContent = dateObj.toLocaleDateString("en", { month: "short", day: "numeric" });

      col.appendChild(value);
      col.appendChild(bar);
      col.appendChild(label);
      statsChart.appendChild(col);
    });
  }

  // ===== Copy to Clipboard =====
  window.copyToClipboard = async function () {
    var text = resultUrl.textContent;
    if (!text) return;

    var copyBtn = document.querySelector(".btn-copy");

    try {
      await navigator.clipboard.writeText(text);
      copyBtn.classList.add("copied");
      copyBtn.querySelector(".copy-label").textContent = "Copied!";
      toast("Copied to clipboard", "success");

      setTimeout(function () {
        copyBtn.classList.remove("copied");
        copyBtn.querySelector(".copy-label").textContent = "Copy";
      }, 2000);
    } catch (err) {
      // Fallback for older browsers
      var textarea = document.createElement("textarea");
      textarea.value = text;
      textarea.style.position = "fixed";
      textarea.style.opacity = "0";
      document.body.appendChild(textarea);
      textarea.select();

      try {
        document.execCommand("copy");
        copyBtn.classList.add("copied");
        copyBtn.querySelector(".copy-label").textContent = "Copied!";
        toast("Copied to clipboard", "success");

        setTimeout(function () {
          copyBtn.classList.remove("copied");
          copyBtn.querySelector(".copy-label").textContent = "Copy";
        }, 2000);
      } catch (copyErr) {
        toast("Failed to copy", "error");
      }

      document.body.removeChild(textarea);
    }
  };

  // ===== Toast Notifications =====
  function toast(message, type) {
    var el = document.createElement("div");
    el.className = "toast toast-" + (type || "success");
    el.textContent = message;
    toastContainer.appendChild(el);

    setTimeout(function () {
      el.classList.add("toast-out");
      el.addEventListener("animationend", function () {
        el.remove();
      });
    }, 3000);
  }

  // ===== Utilities =====
  function escapeHtml(str) {
    var div = document.createElement("div");
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
  }

  function escapeAttr(str) {
    return str.replace(/&/g, "&amp;").replace(/"/g, "&quot;").replace(/'/g, "&#39;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
  }

  function formatDate(dateStr) {
    if (!dateStr) return "-";
    var d = new Date(dateStr);
    if (isNaN(d.getTime())) return dateStr;
    return d.toLocaleDateString("en", { month: "short", day: "numeric", year: "numeric" });
  }

  // ===== Init =====
  loadUrls();
})();

