 3→const fs = require('fs');
 4→
 5→const dataDir = path.join(__dirname, 'data');
 6→if (!fs.existsSync(dataDir)) {
 7→  fs.mkdirSync(dataDir, { recursive: true });
 8→}
 9→
10→const db = new Database(path.join(dataDir, 'urls.db'));
11→
12→db.pragma('journal_mode = WAL');
13→db.pragma('foreign_keys = ON');
14→
15→db.exec(`
16→  CREATE TABLE IF NOT EXISTS urls (
17→    id INTEGER PRIMARY KEY AUTOINCREMENT,
18→    slug TEXT NOT NULL UNIQUE,
19→    original_url TEXT NOT NULL,
20→    clicks INTEGER DEFAULT 0,
21→    created_at TEXT DEFAULT (datetime('now')),
22→    expires_at TEXT
23→  );
24→
25→  CREATE TABLE IF NOT EXISTS click_log (
26→    id INTEGER PRIMARY KEY AUTOINCREMENT,
27→    slug TEXT NOT NULL,
28→    clicked_at TEXT DEFAULT (datetime('now')),
29→    ip TEXT,
30→    user_agent TEXT,
31→    FOREIGN KEY (slug) REFERENCES urls(slug) ON DELETE CASCADE
32→  );
33→
34→  CREATE INDEX IF NOT EXISTS idx_urls_slug ON urls(slug);
35→  CREATE INDEX IF NOT EXISTS idx_click_log_slug ON click_log(slug);
36→`);
37→
38→const stmts = {
39→  insertUrl: db.prepare(
40→    'INSERT INTO urls (slug, original_url, expires_at) VALUES (@slug, @originalUrl, @expiresAt)'
41→  ),
42→  getUrl: db.prepare('SELECT * FROM urls WHERE slug = ?'),
43→  getAllUrls: db.prepare('SELECT * FROM urls ORDER BY created_at DESC'),
44→  incrementClick: db.prepare('UPDATE urls SET clicks = clicks + 1 WHERE slug = ?'),
45→  logClick: db.prepare(
46→    'INSERT INTO click_log (slug, ip, user_agent) VALUES (@slug, @ip, @userAgent)'
47→  ),
48→  deleteUrl: db.prepare('DELETE FROM urls WHERE slug = ?'),
49→  getClickStats: db.prepare(
50→    `SELECT date(clicked_at) AS date, COUNT(*) AS count
51→     FROM click_log
52→     WHERE slug = ?
53→     GROUP BY date(clicked_at)
54→     ORDER BY date(clicked_at) DESC`
55→  ),
